```class Solution {
    public boolean isFascinating(int n) {
        int original = n;
        int twice = n * 2;
        int thrice = n * 3;
        String str = String.valueOf(original) + String.valueOf(twice) + String.valueOf(thrice);
        for (int i = '1'; i <= '9'; i++) {
            if (str.indexOf(String.valueOf(i)) == -1) {
                return false;
            }
        }
        return true;
    }
